// This script converts the provided image into a background element.
document.addEventListener('DOMContentLoaded', function() {
  // 1. We encode the original image into a text-based format called base64.
  // This allows us to embed the image directly in the script.
  // Note: For actual use, you would generate this exact long string
  // from a tool that converts an image file into base64.
  var imageData = '';

  // 2. Inject a fixed full-screen background image — perfectly centered,
  //    behind all other page elements (z-index:-1).
  //    The data URI prefix is added here so the browser can decode the PNG.
  var bg = document.createElement('img');
  bg.src = 'data:image/png;base64,' + imageData;
  bg.setAttribute('aria-hidden', 'true');
  bg.style.cssText = (
    'position:fixed;' +
    'top:0;left:0;' +
    'width:100%;height:100%;' +
    'object-fit:cover;' +
    'object-position:center center;' +
    'z-index:-1;' +
    'pointer-events:none;' +
    'display:block;' +
    'image-rendering:-webkit-optimize-contrast;' +
    'image-rendering:smooth;' +
    'image-rendering:high-quality;' +
    '-ms-interpolation-mode:bicubic;' +
    'transform:translateZ(0);' +
    'will-change:transform;' +
    'filter:contrast(1.04) saturate(1.02);'
  );
  document.body.insertBefore(bg, document.body.firstChild);
});
